import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import MicrosoftTeams from './components/MicrosoftTeams';
import Zoom from './components/Zoom';
import Skype from './components/Skype';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/Chrome';
import WhatsApp from './components/WhatsApp';
import FileExplorer from './components/FileExplorer';
import './App.css';

const App = () => {
  const [activeComponent, setActiveComponent] = useState('fileExplorer');

  return (
    <Router>
      <div className="App">
        <Sidebar setActiveComponent={setActiveComponent} />
        <div className="content">
          {/* Rute pentru Teams, Zoom și Skype */}
          <Routes>
            <Route path="/shortcuts/teams" element={<MicrosoftTeams />} />
            <Route path="/shortcuts/zoom" element={<Zoom />} />
            <Route path="/shortcuts/skype" element={<Skype />} />
          </Routes>

          {/* Restul componentelor gestionate prin activeComponent */}
          {activeComponent === 'fileExplorer' && (
            <FileExplorer setActiveComponent={setActiveComponent} />
          )}
          {activeComponent === 'microsoftWord' && (
            <MicrosoftWord setActiveComponent={setActiveComponent} />
          )}
          {activeComponent === 'microsoftExcel' && (
            <MicrosoftExcel setActiveComponent={setActiveComponent} />
          )}
          {activeComponent === 'powerPoint' && (
            <PowerPoint setActiveComponent={setActiveComponent} />
          )}
          {activeComponent === 'pdfReader' && (
            <PDFReader setActiveComponent={setActiveComponent} />
          )}
          {activeComponent === 'chrome' && (
            <Chrome setActiveComponent={setActiveComponent} />
          )}
          {activeComponent === 'whatsapp' && (
            <WhatsApp setActiveComponent={setActiveComponent} />
          )}
        </div>
      </div>
    </Router>
  );
};

export default App;
